 1	import React, { FC, ReactNode, useEffect, useState } from 'react';
 2	
 3	import { HyperConverged } from '@kubevirt-utils/hooks/useHyperConvergeConfiguration';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Text, TextVariants } from '@patternfly/react-core';
 7	
 8	import ExpandSection from '../../../../ExpandSection/ExpandSection';
 9	import GeneralSettingsError from '../shared/GeneralSettingsError';
10	import GeneralSettingsProjectSelector from '../shared/GeneralSettingsProjectSelector';
11	
12	import '../shared/general-settings.scss';
13	
14	type GeneralSettingsProjectProps = {
15	  description: ReactNode;
16	  hcoResourceNamespace: string;
17	  hyperConvergeConfiguration: [hyperConvergeConfig: HyperConverged, loaded: boolean, error: any];
18	  namespace: string;
19	  onChange: (
20	    hyperConverged: HyperConverged,
21	    newNamespace: null | number | string,
22	    handelError: (value: string) => void,
23	    handleLoading: (value: boolean) => void,
24	  ) => void;
25	  projectsData: [projects: K8sResourceCommon[], loaded: boolean, error: any];
26	  toggleText: string;
27	};
28	
29	const GeneralSettingsProject: FC<GeneralSettingsProjectProps> = ({
30	  description,
31	  hcoResourceNamespace,
32	  hyperConvergeConfiguration,
33	  namespace,
34	  onChange,
35	  projectsData,
36	  toggleText,
37	}) => {
38	  const { t } = useKubevirtTranslation();
39	  const [loading, setLoading] = useState<boolean>(false);
40	  const [selectedProject, setSelectedProject] = useState<string>();
41	  const [error, setError] = useState<string>();
42	
43	  const [hyperConverge, hyperLoaded] = hyperConvergeConfiguration;
44	  const [projects, projectsLoaded, projectsLoadingError] = projectsData;
45	
46	  useEffect(() => {
47	    if (hyperConverge) {
48	      !selectedProject && setSelectedProject(hcoResourceNamespace ?? namespace);
49	    }
50	  }, [hcoResourceNamespace, hyperConverge, namespace, selectedProject]);
51	
52	  const onSelect = (value: string) => {
53	    setError(null);
54	    setSelectedProject(value);
55	    onChange(hyperConverge, value, setError, setLoading);
56	  };
57	
58	  return (
59	    <ExpandSection className="project-tab__main" toggleText={toggleText}>
60	      <Text className="project-tab__main--help" component={TextVariants.small}>
61	        {description}
62	      </Text>
63	      <Text className="project-tab__main--field-title" component={TextVariants.h6}>
64	        {t('Project')}
65	      </Text>
66	      <GeneralSettingsProjectSelector
67	        loaded={!loading && hyperLoaded && projectsLoaded}
68	        onSelect={onSelect}
69	        projects={projects}
70	        selectedProject={selectedProject}
71	      />
72	      <GeneralSettingsError error={error} loading={projectsLoadingError} />
73	    </ExpandSection>
74	  );
75	};
76	
77	export default GeneralSettingsProject;

